import {{ Injectable }} from '@nestjs/common';
import {{ SmsService }} from './models/sms.model';
import {{ SmsServiceRepository }} from './repositories/sms.repository';

@Injectable()
export class SmsServiceService {{
  constructor(
    private readonly repository: SmsServiceRepository,
  ) {{}}

  async findAll(): Promise<SmsService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<SmsService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<SmsService>): Promise<SmsService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<SmsService>): Promise<SmsService> {{
    return this.repository.update(id, data);
  }}
}}
